var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"저더러…… 에델을 막으라고요?","JPN":"私に……エデルを止めろと？","ENG":"You want me... to stop Edel?","TWN":"讓我……阻止艾瑟兒？"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그게 지금 말이 된다고 생각해요…?","JPN":"そんなことが、できるとお思いですか……？","ENG":"You cannot be serious...!","TWN":"你覺得這像話嗎……？"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 꼴을 보세요… 이런 한심한 인간이 뭘 할 수 있는데요…","JPN":"今の私を見てください……こんな情けない人間に、何ができるというのですか……？","ENG":"I mean, look at me... What can a pathetic girl like me do...?","TWN":"看看我這副樣子……我這種可憐人能做什麼……"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 뭘 믿고, 그런 말을……!","JPN":"私の何を信じて、そのような……！","ENG":"How can you say that when–!","TWN":"我憑什麼，相信這種話……！"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 믿고 하는 부탁이라네.","JPN":"君を信じての頼みだ。","ENG":"I'm asking because I trust you.","TWN":"找你幫忙，是因為我相信你。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"인간으로서, 이성을 견지하고 학회와 마주했던 자네 말이야.","JPN":"人間として、理性を堅持し学会と向かい合った君を。","ENG":"You, a human being who stood by reason and faced the Society.","TWN":"相信身為人類仍能堅守本心面對學會的你。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그딴 건 아무짝에도 쓸모없었어요……!","JPN":"そんなものは何の役にも立ちませんでしたわ……！","ENG":"And look where that got me...!","TWN":"這些東西一點用都沒有……！"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아무리 그럴싸한 말도… 아무도 들어 주지 않으면 무슨 소용이냐고요….","JPN":"いくらそれらしい言葉も……聞いてくれる人がいないと無駄なのです……","ENG":"No matter how hard I try to convince them... What use is it when they are not willing to listen?","TWN":"就算再怎麼有道理的話……說出來沒有人聽，又有什麼用……"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양은 정치로 사람들을 움직여 온 사람이었나?","JPN":"マクレディー君は政治で人々を動かしてきた人だったか？","ENG":"Regina, were you one to convince people with politics?","TWN":"麥克蕾蒂是靠政治打動人們的嗎？"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"에델의 계획을 막으려고 프리드웬까지 끌어들였다고요……!","JPN":"エデルの計画を止めるために、プリドウェンまで引き入れました……！","ENG":"I even got the Prydwen Institution involved to stop Edel...!","TWN":"為了阻止艾瑟兒的計畫，我甚至把普利多溫牽扯進來了……！"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아니면 지략과 묘수로 난관을 타개해 왔나?","JPN":"それとも知略や妙策で難関を乗り越えてきたのか？","ENG":"Or, have you overcome difficulties by being resourceful and cunning?","TWN":"還是說你是用智謀和妙計渡過難關的？"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제 힘으로는 에델을 멈출 수 없어요… 학회원들이 득실거릴 텐데 저 혼자 어떻게…!","JPN":"私の力ではエデルを止めることはできません……学会員がうじゃうじゃいるはずなのに、私一人でどうやって……！","ENG":"I could not stop Edel alone... How am I supposed to face all of the Society by myself...?!","TWN":"靠我的力量阻止不了艾瑟兒……學會成員那麼多，我一個人怎麼……！"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"여태까지 힘의 논리로 적을 쓰러뜨렸던 건가?","JPN":"今まで力の論理で敵を倒してきたのか？","ENG":"Have you dominated your enemies using the overwhelming force?","TWN":"難道你以前都是用力量的邏輯打倒敵人的嗎？"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그만해!!","JPN":"やめて！！","ENG":"STOP IT!!","TWN":"不要再說了！！"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 어떡할지 답을 줘! 정답을 알고 있으면서 왜!!","JPN":"それじゃあ、どうするか答えをちょうだい！　正解をわかっているくせになんで！！","ENG":"Then tell me what I should do if you already know the answer!!","TWN":"那你告訴我，我該怎麼辦！你明明知道答案，為什麼不告訴我！！"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그게 자네가 탐식자에게 맞설 수 있는 유일한 수단이니까.","JPN":"それが君が貪食者に立ち向かえる唯一の手だからだ。","ENG":"Because that's the only weapon you have to fight against the Devourer.","TWN":"因為這是你能對抗貪食者的唯一方法。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"맥크레디 양, 실패를 겪고 꺾이는 건 사람인 이상 당연해.","JPN":"マクレディー君、失敗を経験してくじけてしまうのは、人間である以上当然のことだ。","ENG":"Regina, it's natural to get discouraged when you fail.","TWN":"麥克蕾蒂，只要是人，必然會經歷失敗和挫折。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"포기해도 좋아.","JPN":"あきらめてもよい。","ENG":"It's okay to give up.","TWN":"放棄也沒關係。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네를 탓할 자격은 아무에게도 없다네. 자네는 최선을 다해 왔어.","JPN":"誰にも君を責める資格はない。君は最善を尽くしてきた。","ENG":"There is no one who can blame you for that. You have always done your best.","TWN":"任何人都沒有資格責怪你。因為你已經盡力了。"},"stage":{"bg":"ESPR2_05","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};